<template>
    <div class="container">
        <el-breadcrumb separator-class="el-icon-arrow-right">
            <el-breadcrumb-item :to="{ path: '/home' }">首页</el-breadcrumb-item>
            <el-breadcrumb-item>活动管理</el-breadcrumb-item>
            <el-breadcrumb-item>活动列表</el-breadcrumb-item>
        </el-breadcrumb>
        <el-card>
            <el-alert title="添加商品信息" type="info" show-icon :closable=false>
            </el-alert>
            <el-steps :space="300" :active="activeIndex-0" finish-status="success" align-center >
                <el-step title="基本信息"></el-step>
                <el-step title="商品参数"></el-step>
                <el-step title="商品属性"></el-step>
                <el-step title="商品图片"></el-step>
                <el-step title="商品内容"></el-step>
                <el-step title="完成"></el-step>
            </el-steps>
            <el-form :model="addForm" :rules="addFormRules" ref="addFormRef" label-width="100px" label-position='top'>
                <el-tabs :tab-position="'left'" v-model="activeIndex" :before-leave="beforeTabsLeave" @tab-click="tabClicked">
                    <el-tab-pane label="基本信息" name="0">
                        <el-form-item label="商品名称" prop="goods_name">
                            <el-input v-model="addForm.goods_name"></el-input>
                        </el-form-item>
                        <el-form-item label="商品价格" prop="goods_price">
                            <el-input v-model="addForm.goods_price" type="number"></el-input>
                        </el-form-item>
                        <el-form-item label="商品数量" prop="goods_number">
                            <el-input v-model="addForm.goods_number" type="number"></el-input>
                        </el-form-item>
                        <el-form-item label="商品重量" prop="goods_weight">
                            <el-input v-model="addForm.goods_weight" type="number"></el-input>
                        </el-form-item>
                        <el-form-item label="商品分类" prop="goods_cat">
                            <el-cascader v-model="addForm.goods_cat" :options="categoryList" :props="{ expandTrigger: 'hover',label:'cat_name',value:'cat_id',children:'children'}"  @change="handleChange"></el-cascader>
                        </el-form-item>
                    </el-tab-pane>
                    <el-tab-pane label="商品参数" name="1">
                        <el-form-item :label="item.attr_name" v-for="item in manyTableDate" :key="item.attr_id">
                            <template>
                                <el-checkbox-group v-model="item.attr_vals">
                                    <el-checkbox :label="it" v-for="(it ,id) in item.attr_vals" :key="id" border></el-checkbox>
                                </el-checkbox-group>
                            </template>
                        </el-form-item>
                    </el-tab-pane>
                    <el-tab-pane label="商品属性" name="2">
                        <el-form-item :label="item.attr_name" v-for="item in onlyTableDate" :key="item.attr_id">
                            <el-input v-model="item.attr_vals"></el-input>
                        </el-form-item>
                    </el-tab-pane>
                    <el-tab-pane label="商品图片" name="3">
                        <!-- action属性表示要上传图片的接口地址  注意！！！这里组件默认不是通过自己的axios发送数据请求 需要通过headers属性为请求头挂载token字段 -->
                        <!-- preview预览图片处理函数 -->
                        <!-- remove移除图片处理函数 -->
                        <!-- list-type上传图片的列表 -->
                        <el-upload
                            action="http://127.0.0.1:8888/api/private/v1/upload"
                            :on-preview="handlePreview"
                            :on-remove="handleRemove"
                            list-type="picture" :headers="headerToken" :on-success="handleSuccess">
                            <el-button size="small" type="primary">点击上传</el-button>
                            <!-- 提示消息感觉不需要 -->
                            <!-- <div slot="tip" class="el-upload__tip">只能上传jpg/png文件，且不超过500kb</div> -->
                        </el-upload>
                    </el-tab-pane>
                    <el-tab-pane label="商品内容" name="4">
                        <!-- 富文本编辑器 -->
                        <quill-editor v-model="addForm.goods_introduce"></quill-editor>
                        <el-button  type="primary" class="btnAdd" @click="addGoods">添加商品</el-button>
                    </el-tab-pane>
                </el-tabs>
            </el-form>
        </el-card>

        <el-dialog title="图片预览" :visible.sync="previewDialogVisible" width="50%" >
            <img :src="previewImageUrl" alt="" class="preview">
        </el-dialog>
    </div>
</template>

<script>
// 导入深拷贝的包
import _ from 'lodash'

export default{
    data(){
        return{
            activeIndex:'0',
            addForm:{
                goods_name:'',
                goods_cat:[],
                goods_price:0,
                goods_number:0,
                goods_weight:0,
                goods_introduce:'',
                pics:[],
                attrs:[],
            },
            categoryList:[],
            manyTableDate:[],
            onlyTableDate:[],
            previewDialogVisible:false,
            previewImageUrl:'',
            headerToken:{Authorization:window.sessionStorage.getItem('token')},
            addFormRules:{
                goods_name:[
                    { required: true, message: '请输入商品名称', trigger: 'blur' },
                ],
                goods_price:[
                    { required: true, message: '请输入商品价格', trigger: 'blur' },
                ],
                goods_number:[
                    { required: true, message: '请输入商品数量', trigger: 'blur' },
                ],
                goods_weight:[
                    { required: true, message: '请输入商品重量', trigger: 'blur' },
                ],
                goods_cat:[
                    { required: true, message: '请选择商品分类', trigger: 'blur' },
                ]
            }
        }
    },
    created(){
        this.getCategoryList()
    },
    methods:{
        async getCategoryList(){
            const{data:result}=await this.$http.get(`categories`)
            if(result.meta.status!==200){return this.$message.error(result.meta.msg);}
            else{this.$message.success(result.meta.msg);}
            this.categoryList=result.data
            // console.log(result.data);
        },
        handleChange(){
            // 只允许选择三级分类
            if(this.addForm.goods_cat.length!==3){
                this.addForm.goods_cat=[]
                return
            }
        },
        beforeTabsLeave(activeName,oldActiveName){
            if(oldActiveName==='0'&& this.addForm.goods_cat.length!==3){
                this.$message.error('请选择三级分类')
                // 验证不通过！阻止！
                return false
            }
            // 否则验证通过！放行
            return true
        },
        async tabClicked(){
            // 处理函数自带的属性
            // console.log(this.activeIndex);
            if(this.activeIndex==='1'){
                // 发起请求
                const{data:result}=await this.$http.get(`categories/${this.cateID}/attributes`,{params:{sel:'many'}})
                if(result.meta.status!==200){return this.$message.error(result.meta.msg);}
                else{this.$message.success(result.meta.msg);}
                
                result.data.forEach(item =>{
                    // console.log(item.attr_vals.length);
                    item.attr_vals=item.attr_vals.length===0?[]:item.attr_vals.split(',')
                })

                // console.log(result.data);
                this.manyTableDate=result.data
            }
            else if(this.activeIndex==='2'){
                const{data:result}=await this.$http.get(`categories/${this.cateID}/attributes`,{params:{sel:'only'}})
                if(result.meta.status!==200){return this.$message.error(result.meta.msg);}
                else{this.$message.success(result.meta.msg);}
                // console.log(result.data);
                this.onlyTableDate=result.data
            }
        },
        handlePreview(file){
            this.previewDialogVisible=true
            this.previewImageUrl=file.response.data.url
        },
        handleRemove(file){
            // console.log(file);
            const filePath=file.response.data.tmp_path
            const index=this.addForm.pics.findIndex(item=>{
                item.pic===filePath
            })
            this.addForm.pics.splice(index,1)
            console.log(this.addForm);
        },
        handleSuccess(response, file, fileList){
            this.addForm.pics.push({pic:response.data.tmp_path})
            // console.log(this.addForm);
        },
        addGoods(){
            // console.log(this.addForm);
            // 验证这几个表单页签的数据
            this.$refs.addFormRef.validate(async valid=>{
                if(!valid){
                    return this.$message.error('请填写必要的表单项')
                }
                this.manyTableDate.forEach(item=>{
                    const manyDate={
                        attr_id:item.attr_id,
                        attr_value:item.attr_vals.join(',')
                    }
                    this.addForm.attrs.push(manyDate)
                })
                this.onlyTableDate.forEach(item=>{
                    const onlyDate={
                        attr_id:item.attr_id,
                        attr_value:item.attr_vals
                    }
                    this.addForm.attrs.push(onlyDate)
                })
                // 队addForm中的数据进行最后的处理,数据浅拷贝
                const newAddForm=_.cloneDeep(this.addForm)
                newAddForm.goods_cat=newAddForm.goods_cat.join(',')
                // console.log(newAddForm);
                // 发添加商品的请求
                const{data:result}=await this.$http.post(`goods`,newAddForm)
                if(result.meta.status!==201){return this.$message.error(result.meta.msg);}
                else{this.$message.success(result.meta.msg);}
                this.$router.push('/goods')
            })
        }
    },
    computed:{
        cateID(){
            if(this.addForm.goods_cat.length!==3){
                return null
            }
            else return this.addForm.goods_cat[2]
        }
    }
}
</script>

<style lang="less" scoped>
.container{
    padding: 20px;
    width: 100%;
    background-color: aliceblue;
    box-sizing: border-box;
    .el-breadcrumb{
        font-size: 12px;
    }
    .el-card{
        margin: 20px 0 20px 0;
        padding: 10px;
        .el-steps{
            transform: translateY(10px);
        }
        .el-tabs{
            margin-top: 20px;
        }
        .el-checkbox{
            margin: 0 10px 0 0;
        }
        .btnAdd{
            margin-top: 10px;
        }
    }
    .preview{
           max-width: 100%;
           max-height: 100%;
           display: block;
           margin: auto;
        }
}
</style>