<template>
    <div class="container">
        <el-breadcrumb separator-class="el-icon-arrow-right">
            <el-breadcrumb-item :to="{ path: '/home' }">首页</el-breadcrumb-item>
            <el-breadcrumb-item>活动管理</el-breadcrumb-item>
            <el-breadcrumb-item>活动列表</el-breadcrumb-item>
        </el-breadcrumb>
        <el-card>
            <el-row :gutter="20">
                <el-col :span="8">
                    <!-- @input="change($event)解决输入框嵌套太深失效的问题 -->
                        <el-input v-model="queryInfo.query" clearable @input="change($event)" @clear="getGoodsList()">
                            <el-button slot="append" icon="el-icon-search" @click="getGoodsList()"></el-button>
                        </el-input>
                </el-col>
                <el-col :span="4">
                    <el-button type="primary" @click="goAddGoodsPage">添加商品</el-button>
                </el-col>
            </el-row>
            <el-table border stripe :data="goodsList">
                <!-- <el-table-column type="expand"></el-table-column> -->
                <el-table-column type="index" label="顺序"></el-table-column>
                <el-table-column prop="goods_name" label="商品名称" width="400"></el-table-column>
                <el-table-column prop="goods_price" label="商品价格"></el-table-column>
                <el-table-column prop="goods_weight" label="商品重量"></el-table-column>
                <el-table-column prop="add_time" label="创建时间" width="180">
                    <template slot-scope="scope">
                        {{scope.row.add_time | dateFormate}}
                    </template>
                </el-table-column>
                <el-table-column label="操作" width="120">
                    <template slot-scope="scope">
                        <el-button type="primary" icon="el-icon-edit" size="mini"></el-button>
                        <el-button type="danger" icon="el-icon-delete" size="mini" @click="DeleteGoods(scope.row)"></el-button>
                    </template>
                </el-table-column>
            </el-table>
            <el-pagination
                    @size-change="handleSizeChange"
                    @current-change="handleCurrentChange"
                    :current-page="queryInfo.pagenum"
                    :page-sizes="[2, 5, 10, 20]"
                    :page-size="100"
                    layout="total, sizes, prev, pager, next, jumper"
                    :total="total">
                </el-pagination>
        </el-card>
    </div>
</template>

<script>

export default{
    data(){
        return{
            queryInfo:{
                query:'',
                pagenum:1,
                pagesize:10
            },
            goodsList:[],
            pagenum:null,
            total:null
        }
    },
    created(){
        this.getGoodsList()
    },
    methods:{
        async getGoodsList(){
            const{data:result}=await this.$http.get(`goods`,{params:this.queryInfo})
            if(result.meta.status!==200){return this.$message.error(result.meta.msg);}
            else{this.$message.success(result.meta.msg);}
            // console.log(result.data);
            this.goodsList=result.data.goods
            this.pagenum=result.data.pagenum
            this.total=result.data.total
        },
        handleSizeChange(size){
            this.queryInfo.pagesize=size
            this.getGoodsList()
        },
        handleCurrentChange(page){
            this.queryInfo.pagenum=page
            this.getGoodsList()
        },
        change(e){
            this.$forceUpdate()
        },
        DeleteGoods(row){
            this.$confirm('此操作将永久删除该文件, 是否继续?', '提示', {
                confirmButtonText: '确定',
                cancelButtonText: '取消',
                type: 'warning'
            }).then(async ()=>{
                // console.log(row.goods_id);
                const{data:result}=await this.$http.delete(`goods/${row.goods_id}`)
                if(result.meta.status!==200){return this.$message.error(result.meta.msg);}
                else{this.$message.success(result.meta.msg);}
                this.getGoodsList()
            }).catch(err=>{
                return err
            }) 
        },
        goAddGoodsPage(){
            this.$router.push('/goods/add')
        }
    },
}
</script>

<style lang="less" scoped>
.container{
    padding: 20px;
    width: 100%;
    background-color: aliceblue;
    box-sizing: border-box;
    .el-breadcrumb{
        font-size: 12px;
    }
    .el-card{
        margin: 20px 0 20px 0;
        padding: 10px;
        .el-table{
            margin-top: 20px;
        }
        .el-pagination{
            margin-left: 50%;
            transform: translate(-50%,10px);
        }
    }
}
</style>